module shift_register(clk, reset, load, data_in, shift_out, data_out);

	input clk;
	input reset;
	input load;
	input [3:0] data_in;
	output shift_out;
	output [3:0] data_out;

	reg [3:0] shadow_reg;

	always @(posedge clk) begin
		if (reset) begin
			shadow_reg <= 4'b0;
		end else if (load) begin
			shadow_reg <= data_in;
		end else begin
			shadow_reg[3] <= shadow_reg[2];
			shadow_reg[2] <= shadow_reg[1];
			shadow_reg[1] <= shadow_reg[0];
			shadow_reg[0] <= 1'b0;
		end
	end

	assign shift_out = shadow_reg[3];
	assign data_out = shadow_reg;

endmodule
